def save_results_to_s3(results, source_key):
    """
    Save processing results as JSON to the results S3 bucket.

    Args:
        results: dict of processing results
        source_key: original image S3 key (used to derive results key)

    Returns:
        str: the S3 key where results were saved
    """
    # Create a results key based on the source key
    base_name = os.path.splitext(os.path.basename(source_key))[0]
    timestamp = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
    results_key = f"results/{base_name}_{timestamp}.json"

    results_json = json.dumps(results, indent=2, default=str)

    logger.info(f"Saving results to s3://{RESULTS_BUCKET}/{results_key}")

    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=results_key,
            Body=results_json.encode('utf-8'),
            ContentType='application/json',
            Metadata={
                'source-key': source_key,
                'processed-at': results.get('processed_at', '')
            }
        )
        logger.info(f"Results saved successfully to s3://{RESULTS_BUCKET}/{results_key}")
        return results_key
    except Exception as e:
        logger.error(f"Error saving results to S3: {str(e)}")
        raise


def send_notification(subject, message):
    """
    Send a notification via SNS.

    Args:
        subject: notification subject line
        message: notification body (string or dict)
    """
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return

    if isinstance(message, dict):
        message_body = json.dumps(message, indent=2, default=str)
    else:
        message_body = str(message)

    logger.info(f"Sending SNS notification: subject='{subject}'")

    try:
        response = sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject limit is 100 chars
            Message=message_body,
            MessageAttributes={
                'event_type': {
                    'DataType': 'String',
                    'StringValue': 'image_processing'
                }
            }
        )
        logger.info(f"SNS notification sent: MessageId={response['MessageId']}")
    except Exception as e:
        # Don't fail the whole process if notification fails
        logger.error(f"Error sending SNS notification: {str(e)}")


def send_error_notification(source_bucket, source_key, error):
    """Send an SNS notification for processing errors."""
    send_notification(
        subject="Image Processing Error",
        message={
            'status': 'error',
            'source_bucket': source_bucket,
            'source_key': source_key,
            'error': str(error),
            'timestamp': datetime.utcnow().isoformat() + 'Z'
        }
    )


def lambda_handler(event, context):
    """
    Main Lambda handler triggered by S3 events.

    Expected trigger: S3 PUT/POST event on the upload bucket.

    Args:
        event: S3 event notification payload
        context: Lambda context object

    Returns:
        dict with processing status and results
    """
    logger.info(f"Lambda invoked: request_id={context.aws_request_id}")
    logger.info(f"Event received: {json.dumps(event, default=str)}")

    results_summary = []
    errors = []

    # Handle S3 event records (may contain multiple records)
    records = event.get('Records', [])

    if not records:
        logger.warning("No records found in event")
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'No records in event'})
        }

    for record in records:
        source_bucket = None
        source_key = None

        try:
            # Extract S3 event information
            event_name = record.get('eventName', '')
            s3_info = record.get('s3', {})
            source_bucket = s3_info.get('bucket', {}).get('name', '')
            source_key = unquote_plus(
                s3_info.get('object', {}).get('key', '')
            )

            logger.info(
                f"Processing record: event={event_name}, "
                f"bucket={source_bucket}, key={source_key}"
            )

            # Validate the file is a supported image format
            if not validate_image_key(source_key):
                logger.warning(
                    f"Unsupported file format, skipping: {source_key}"
                )
                continue

            # Skip if the object is in the results bucket (prevent loops)
            if source_bucket == RESULTS_BUCKET:
                logger.warning(
                    "Object is in results bucket, skipping to prevent loop"
                )
                continue

            # Step 1: Fetch image from S3
            image_data = get_image_from_s3(source_bucket, source_key)

            # Step 2: Process the image
            processing_results = process_image(image_data, source_key)
            processing_results['source_bucket'] = source_bucket

            # Step 3: Save results to S3
            results_key = save_results_to_s3(processing_results, source_key)
            processing_results['results_key'] = results_key

            # Step 4: Send success notification
            send_notification(
                subject=f"Image Processed: {os.path.basename(source_key)}",
                message={
                    'status': 'success',
                    'source_bucket': source_bucket,
                    'source_key': source_key,
                    'results_bucket': RESULTS_BUCKET,
                    'results_key': results_key,
                    'detected_format': processing_results.get('detected_format'),
                    'file_size_bytes': processing_results.get('file_size_bytes'),
                    'processed_at': processing_results.get('processed_at')
                }
            )

            results_summary.append({
                'source_key': source_key,
                'results_key': results_key,
                'status': 'success'
            })

            logger.info(f"Successfully processed: {source_key}")

        except ImageProcessingError as e:
            logger.error(f"Image processing error for {source_key}: {str(e)}")
            errors.append({
                'source_key': source_key,
                'error': str(e),
                'error_type': 'ImageProcessingError'
            })
            send_error_notification(source_bucket, source_key, e)

        except Exception as e:
            logger.error(
                f"Unexpected error processing {source_key}: {str(e)}",
                exc_info=True
            )
            errors.append({
                'source_key': source_key,
                'error': str(e),
                'error_type': type(e).__name__
            })
            send_error_notification(source_bucket, source_key, e)

    # Build response
    response = {
        'statusCode': 200 if not errors else 207,  # 207 Multi-Status if partial
        'body': json.dumps({
            'request_id': context.aws_request_id,
            'records_received': len(records),
            'records_processed': len(results_summary),
            'records_failed': len(errors),
            'results': results_summary,
            'errors': errors
        }, default=str)
    }

    logger.info(
        f"Lambda execution complete: processed={len(results_summary)}, "
        f"errors={len(errors)}"
    )

    return response